  create policy "public_presences_all"
  on "public"."presences"
  as permissive
  for all
  to public
using (true)
with check (true);



  create policy "segments_all_public"
  on "public"."segments"
  as permissive
  for all
  to public
using (true)
with check (true);



  create policy "delete_workshop_access_public"
  on "public"."workshop_access"
  as permissive
  for delete
