using (true);



  create policy "update_writing_workshops_all"
  on "public"."writing_workshops"
  as permissive
  for update
  to public
using ((status = ANY (ARRAY['draft'::text, 'published'::text])))
with check ((status = ANY (ARRAY['draft'::text, 'published'::text])));



